package br.com.pueria.pueria.desenvolvimento.dominio;
import java.time.LocalDateTime; import java.util.UUID;
public record HistoricoRespostaMarcoDesenvolvimento(UUID id,UUID criancaId,UUID marcoId,StatusMarcoDesenvolvimento statusAnterior,StatusMarcoDesenvolvimento statusNovo,String observacaoAnterior,String observacaoNova,ModalidadeRegistroMarcoDesenvolvimento modalidade,LocalDateTime registradoEm){ public static HistoricoRespostaMarcoDesenvolvimento registrar(UUID criancaId,UUID marcoId,RegistroMarcoDesenvolvimento anterior,RegistroMarcoDesenvolvimento atual){return new HistoricoRespostaMarcoDesenvolvimento(UUID.randomUUID(),criancaId,marcoId,anterior==null?null:anterior.getStatus(),atual.getStatus(),anterior==null?null:anterior.getObservacao(),atual.getObservacao(),atual.getModalidade(),LocalDateTime.now());} }
